mcqs.question:
What is printed by the following code?
class Base { public: void show() { cout << "Base"; } };
class Derived : public Base { public: void show() { cout << "Derived"; } };
int main() { Base *b = new Derived(); b->show(); }

What is the output?
class A { public: virtual void f() { cout << "A"; } };
class B : public A { public: void f() { cout << "B"; } };
int main() { A *p = new B(); p->f(); }

What is the output?
class Base { public: virtual void print()=0; };
class Derived : public Base { public: void print() { cout << "Hi"; } };
int main() { Derived d; d.print(); }

What is the output?
class A { public: virtual void f() { cout << 1; } };
class B : public A { public: virtual void f() { cout << 2; } };
class C : public B { public: void f() { cout << 3; } };
int main() { A *p = new C(); p->f(); }
